// =============================================================================
// Identity Fetcher - Transform Sheet Rows to Clean JSON
// =============================================================================
// This code transforms Google Sheets rows into a clean JSON object.
// 
// Expected input format (each row from Google Sheets):
//   { "field_name": "full_name", "field_value": "John Doe" }
//   { "field_name": "email", "field_value": "john@example.com" }
//
// Output format:
//   { "full_name": "John Doe", "email": "john@example.com", ... }
// =============================================================================

// Get all items from Google Sheets
const items = $input.all();

// Transform array of rows into a single clean object
const userProfile = {};

for (const item of items) {
  const data = item.json;

  // Handle different possible column naming conventions
  const fieldName = data.field_name || data.Field_Name || data.FieldName || data.key || data.Key;
  const fieldValue = data.field_value || data.Field_Value || data.FieldValue || data.value || data.Value;

  if (fieldName && fieldValue !== undefined) {
    // Convert field name to snake_case for consistency
    const cleanKey = fieldName
      .toLowerCase()
      .trim()
      .replace(/\s+/g, '_')      // Replace spaces with underscores
      .replace(/[^a-z0-9_]/g, '') // Remove special characters
      .replace(/_+/g, '_');       // Remove duplicate underscores

    userProfile[cleanKey] = fieldValue;
  }
}

// Add metadata
const result = {
  success: true,
  fetched_at: new Date().toISOString(),
  profile: userProfile,
  field_count: Object.keys(userProfile).length
};

// Return as single item for downstream workflows
return [{ json: result }];
